// ===== EDIT THIS: role -> the TikTok accounts (Upload-Post profiles) =====
// user           = the Upload-Post profile name for that connected TikTok account
// country        = label only (geo is fixed when you CONNECT the account from
//                  that country's IP - not set here)
// caption_suffix = appended to the caption for THIS account so the same video
//                  isn't posted with an identical caption across many accounts
//                  (a spam-cluster signal). Use unique hashtags.
const ACCOUNT_MAP = {
  narator: [
    { user: 'ro_narator_01', country: 'RO', caption_suffix: '' },
    // { user: 'de_narator_01', country: 'DE', caption_suffix: ' #fyp #deutschland' },
  ],
  comentator: [
    { user: 'ro_comentator_01', country: 'RO', caption_suffix: '' },
  ],
  povestitor: [
    { user: 'ro_povestitor_01', country: 'RO', caption_suffix: '' },
  ],
};

const ROLE_FIELDS = { narator: 'narator_url', comentator: 'comentator_url', povestitor: 'povestitor_url' };

// Read the FULL ready rows from the filter node (the claim node's output is thin).
const rows = $('Only status = ready').all();
const out = [];
for (const item of rows) {
  const row = item.json;
  const caption = (row.DESCRIERE || '').toString().trim();
  const nr = row.NR;
  for (const role of Object.keys(ROLE_FIELDS)) {
    const cell = (row[ROLE_FIELDS[role]] || '').toString().trim();
    if (!cell) continue;
    const urls = cell.split(/\r?\n/).map(s => s.trim()).filter(Boolean); // split parts -> several
    const accounts = ACCOUNT_MAP[role] || [];
    urls.forEach((video_url, partIdx) => {
      for (const acct of accounts) {
        out.push({ json: {
          NR: nr, role, part: partIdx + 1,
          user: acct.user, country: acct.country || '',
          video_url,
          title: (caption + (acct.caption_suffix || '')).slice(0, 2200),
        } });
      }
    });
  }
}
return out;

// Zip each job with its HTTP response (same order), group by NR, decide status.
const jobs = $('Build post jobs').all();
const resps = $input.all();
const byRow = {};
for (let i = 0; i < jobs.length; i++) {
  const j = jobs[i].json;
  const r = (resps[i] && resps[i].json) ? resps[i].json : {};
  let body = (r.body !== undefined) ? r.body : r; // fullResponse -> {statusCode, body}
  let ok = false, msg = '';
  try {
    const b = (typeof body === 'string') ? JSON.parse(body) : body;
    ok = !!(b && (b.success === true || (b.results && b.results.tiktok && b.results.tiktok.success === true)));
    msg = (b && b.message) ? b.message : (ok ? '' : 'failed');
  } catch (e) { msg = 'unparseable response'; }
  const nr = j.NR;
  if (!byRow[nr]) byRow[nr] = { NR: nr, total: 0, ok: 0, errs: [] };
  byRow[nr].total++;
  if (ok) byRow[nr].ok++; else byRow[nr].errs.push((j.role || '') + '/' + (j.user || '') + ': ' + msg);
}
return Object.values(byRow).map(r => ({ json: {
  NR: r.NR,
  status: (r.total > 0 && r.ok === r.total) ? 'posted' : ('error: ' + r.errs.join(' | ')).slice(0, 250),
} }));
